function checkGoodLine(board, r, c, color, dr, dc) {
    let oppColor = color === 'W' ? 'B' : 'W';
    let count = 0;
    r += dr;
    c += dc;
    while (r >= 0 && r < 8 && c >= 0 && c < 8 && board[r][c] === oppColor) {
        count++;
        r += dr;
        c += dc;
    }
    return r >= 0 && r < 8 && c >= 0 && c < 8 && board[r][c] === color && count >= 2;
}

function isLegalMove(board, rMove, cMove, color) {
    if (board[rMove][cMove] !== '.') return false;
    board[rMove][cMove] = color;
    for (let dr = -1; dr <= 1; dr++) {
        for (let dc = -1; dc <= 1; dc++) {
            if (!(dr === 0 && dc === 0) && checkGoodLine(board, rMove, cMove, color, dr, dc)) {
                return true;
            }
        }
    }
    return false;
}
```

    The algorithm works as follows:

1. Check if the given cell is free, marked by '.'. If not, return false.
2. Change the given cell to the given color (white or black).
3. Iterate through all the neighboring cells in 8 directions (up, down, left, right, and four diagonals).
4. For each direction, use a helper function `check_good_line` which:
    a. Initializes a counter to 0.
    b. Moves in the given direction, checking if the next cell is of the opposite color.
    c. If it is, increment the counter and continue moving in the same direction.
    d. If it's not, break the loop and check if the last cell found is of the same color, and if the counter is greater than or equal to 2.
    e. If so, return true. Otherwise, return false.
5. If any of the directions return true from the helper function, the move is legal, so return true from the main function. Otherwise, return false.

