public boolean checkGoodLine(char[][] board, int r, int c, char color, int dr, int dc) {
    char oppColor = color == 'W' ? 'B' : 'W';
    int count = 0;
    r += dr;
    c += dc;
    while (r >= 0 && r < 8 && c >= 0 && c < 8 && board[r][c] == oppColor) {
        count++;
        r += dr;
        c += dc;
    }
    return r >= 0 && r < 8 && c >= 0 && c < 8 && board[r][c] == color && count >= 2;
}

public boolean isLegalMove(char[][] board, int rMove, int cMove, char color) {
    if (board[rMove][cMove] != '.') return false;
    board[rMove][cMove] = color;
    for (int dr = -1; dr <= 1; dr++) {
        for (int dc = -1; dc <= 1; dc++) {
            if (!(dr == 0 && dc == 0) && checkGoodLine(board, rMove, cMove, color, dr, dc)) {
                return true;
            }
        }
    }
    return false;
}
